import React, { useState } from 'react';
import { Scenario, SimulationMessage } from '../types';
import { evaluateAdvocacyResponse } from '../services/geminiService';
import { Send, RefreshCw, MessageSquare, AlertCircle, CheckCircle, Lightbulb } from 'lucide-react';

const SCENARIOS: Scenario[] = [
  {
    id: '1',
    title: 'The "Drug Seeking" Label',
    description: 'A 24-year-old male presents to the ED with 10/10 pain. The triage nurse rolls her eyes and says, "He is here every week for Dilaudid."',
    clinicalContext: 'Patient has a known history of HbSS. Vitals: HR 110, BP 145/90, SpO2 94% on RA. He is writhing in pain. No signs of respiratory depression. Guidelines indicate rapid initiation of analgesia.',
    biasChallenge: 'Overcoming the "frequent flyer" stigma and ensuring timely pain management despite staff skepticism.'
  },
  {
    id: '2',
    title: 'Dismissed Symptoms',
    description: 'A 19-year-old female complains of new chest pain and shortness of breath. The attending says, "It is probably just her usual crisis pain/anxiety."',
    clinicalContext: 'Patient has Acute Chest Syndrome risk. New hypoxia (dropped from 99% to 92%). Attending is busy and dismissive.',
    biasChallenge: 'Advocating for a full workup (CXR, blood gas) for a potentially life-threatening complication labeled as "anxiety".'
  }
];

const Simulator: React.FC = () => {
  const [activeScenario, setActiveScenario] = useState<Scenario | null>(null);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<SimulationMessage[]>([]);
  const [loading, setLoading] = useState(false);

  const handleStartScenario = (scenario: Scenario) => {
    setActiveScenario(scenario);
    setMessages([]);
    setInput('');
  };

  const handleReset = () => {
    setActiveScenario(null);
    setMessages([]);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !activeScenario) return;

    const userMsg: SimulationMessage = { role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const feedback = await evaluateAdvocacyResponse(activeScenario, input);

    const aiMsg: SimulationMessage = {
      role: 'ai',
      text: "I've analyzed your advocacy approach.",
      feedback: feedback
    };

    setMessages(prev => [...prev, aiMsg]);
    setLoading(false);
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8 h-[calc(100vh-64px)] flex flex-col">
      <div className="mb-6">
        <h2 className="text-3xl font-bold text-slate-900">Clinical Advocacy Simulator</h2>
        <p className="text-slate-600">Select a scenario to practice your advocacy skills. The AI will evaluate your empathy, evidence usage, and assertiveness.</p>
      </div>

      {!activeScenario ? (
        <div className="grid md:grid-cols-2 gap-6">
          {SCENARIOS.map((scenario) => (
            <div key={scenario.id} className="bg-white border border-slate-200 rounded-xl p-6 hover:border-red-400 hover:shadow-md transition-all cursor-pointer group" onClick={() => handleStartScenario(scenario)}>
              <h3 className="text-xl font-bold text-slate-900 group-hover:text-red-600 mb-2">{scenario.title}</h3>
              <p className="text-slate-600 mb-4">{scenario.description}</p>
              <div className="flex items-center text-sm font-medium text-red-600">
                Start Simulation <Send className="ml-2 h-4 w-4" />
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="flex-grow flex flex-col md:flex-row gap-6 h-full overflow-hidden">
          {/* Left Panel: Scenario Context */}
          <div className="md:w-1/3 bg-slate-50 p-6 rounded-xl border border-slate-200 overflow-y-auto">
            <button onClick={handleReset} className="text-sm text-slate-500 hover:text-slate-900 flex items-center mb-4">
              <RefreshCw className="h-3 w-3 mr-1" /> Choose different scenario
            </button>
            <h3 className="text-lg font-bold text-slate-900 mb-4">{activeScenario.title}</h3>

            <div className="space-y-4">
              <div className="bg-white p-4 rounded-lg border border-slate-100 shadow-sm">
                <span className="text-xs font-semibold text-slate-400 uppercase tracking-wider">The Situation</span>
                <p className="text-slate-700 mt-1">{activeScenario.description}</p>
              </div>

              <div className="bg-blue-50 p-4 rounded-lg border border-blue-100">
                <span className="text-xs font-semibold text-blue-600 uppercase tracking-wider flex items-center">
                  <ActivityIcon className="h-3 w-3 mr-1" /> Clinical Context
                </span>
                <p className="text-blue-900 text-sm mt-1">{activeScenario.clinicalContext}</p>
              </div>

              <div className="bg-red-50 p-4 rounded-lg border border-red-100">
                <span className="text-xs font-semibold text-red-600 uppercase tracking-wider flex items-center">
                  <AlertCircle className="h-3 w-3 mr-1" /> The Challenge
                </span>
                <p className="text-red-900 text-sm mt-1">{activeScenario.biasChallenge}</p>
              </div>
            </div>
          </div>

          {/* Right Panel: Chat Interface */}
          <div className="md:w-2/3 flex flex-col bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex-grow p-6 overflow-y-auto space-y-6">
              {messages.length === 0 && (
                <div className="text-center text-slate-400 mt-20">
                  <MessageSquare className="h-12 w-12 mx-auto mb-3 opacity-20" />
                  <p>Type exactly what you would say to your colleague or the patient in this situation.</p>
                </div>
              )}

              {messages.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.role === 'user' ? (
                    <div className="bg-slate-900 text-white px-5 py-3 rounded-2xl rounded-tr-none max-w-[90%]">
                      <p className="text-sm">{msg.text}</p>
                    </div>
                  ) : (
                    <div className="w-full">
                      {/* AI Feedback Card */}
                      {msg.feedback && (
                        <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm mt-2">
                          <div className="bg-indigo-50 px-4 py-2 border-b border-indigo-100 flex justify-between items-center">
                            <span className="font-semibold text-indigo-900 text-sm">Advocacy Analysis</span>
                            <span className="text-xs bg-white text-indigo-700 px-2 py-0.5 rounded border border-indigo-200">AI Mentor</span>
                          </div>

                          <div className="p-4 grid grid-cols-3 gap-4 border-b border-slate-100">
                             <ScoreCard label="Empathy" score={msg.feedback.empathyScore} />
                             <ScoreCard label="Evidence" score={msg.feedback.evidenceScore} />
                             <ScoreCard label="Assertiveness" score={msg.feedback.assertivenessScore} />
                          </div>

                          <div className="p-4 space-y-4">
                            <div>
                              <h5 className="text-sm font-semibold text-slate-800 flex items-center mb-1">
                                <Lightbulb className="h-4 w-4 text-amber-500 mr-2" /> Critique
                              </h5>
                              <p className="text-sm text-slate-600">{msg.feedback.critique}</p>
                            </div>

                            <div className="bg-green-50 p-3 rounded-lg border border-green-100">
                              <h5 className="text-xs font-bold text-green-700 flex items-center mb-1 uppercase tracking-wide">
                                <CheckCircle className="h-3 w-3 mr-2" /> Try saying this instead:
                              </h5>
                              <p className="text-sm text-green-800 italic">"{msg.feedback.betterAlternative}"</p>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              ))}

              {loading && (
                <div className="flex items-start">
                   <div className="bg-slate-100 px-4 py-3 rounded-2xl rounded-tl-none animate-pulse">
                     <div className="h-2 w-12 bg-slate-300 rounded"></div>
                   </div>
                </div>
              )}
            </div>

            <div className="p-4 border-t border-slate-100 bg-slate-50">
              <form onSubmit={handleSubmit} className="flex gap-2">
                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  placeholder="Type your response here..."
                  className="flex-grow rounded-lg border-slate-300 shadow-sm focus:border-red-500 focus:ring-red-500 px-4 py-2 border"
                  disabled={loading}
                />
                <button
                  type="submit"
                  disabled={loading || !input.trim()}
                  className="bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                >
                  <Send className="h-5 w-5" />
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const ActivityIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
);

const ScoreCard = ({ label, score }: { label: string, score: number }) => {
  let colorClass = "text-yellow-600";
  if (score >= 8) colorClass = "text-green-600";
  if (score <= 4) colorClass = "text-red-600";

  return (
    <div className="text-center">
      <div className={`text-xl font-bold ${colorClass}`}>{score}/10</div>
      <div className="text-xs text-slate-500 font-medium uppercase tracking-wide">{label}</div>
    </div>
  );
}

export default Simulator;

